          {
            "_key": "54065c5e77f4",
            "_type": "span",
            "marks": [],
            "text": "Doctors can communicate with other doctors and participants in groups or individually via text messaging, audio, and video conversations. Doctors can also view an overview of other doctors and participants quickly with a popup modal."
          }
