    "prototypeBlock": [
      {
        "_key": "2cb8479d6bd0",
        "_type": "block",
        "children": [
          {
            "_key": "b47a4d2ca60e0",
            "_type": "span",
            "marks": [],
            "text": "We designed the sketches with the "
          },
          {
            "_key": "b47a4d2ca60e1",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "\"Crazy 8\""
          },
          {
            "_key": "b47a4d2ca60e2",
            "_type": "span",
            "marks": [],
            "text": " technique then presented them to the group and voted. After all the decisions, we proceeded with paper prototyping and then turned them into digital wireframes."
          }
        ],
        "markDefs": [],
        "style": "normal"
      }
    ],
    "prototypeTitle": "Sketches, Paper Prototypes and Wireframes",
    "prototypeTitle2": null,
