    "designSystem": [
      {
        "_key": "8a99c8d58939",
        "_type": "block",
        "children": [
          {
            "_key": "56c80ef33b9d0",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "The Name"
          },
          {
            "_key": "56c80ef33b9d1",
            "_type": "span",
            "marks": [],
            "text": "\nThe app's name "
          },
          {
            "_key": "56c80ef33b9d2",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "\"瓜田\""
          },
          {
            "_key": "56c80ef33b9d3",
            "_type": "span",
            "marks": [],
            "text": " which directly translates to "
          },
          {
            "_key": "56c80ef33b9d4",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "\"Melon Field\""
          },
          {
            "_key": "56c80ef33b9d5",
            "_type": "span",
            "marks": [],
            "text": " but the intended translation should be "
          },
          {
            "_key": "56c80ef33b9d6",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "\"Melon Eater\""
          },
          {
            "_key": "56c80ef33b9d7",
            "_type": "span",
            "marks": [],
            "text": " which comes from a Chinese slang term often used humorously, onlooker to be exact. Now you may wonder why not just use the Chinese characters for "
          },
          {
            "_key": "56c80ef33b9d8",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "\"Melon Eater\""
          },
          {
            "_key": "56c80ef33b9d9",
            "_type": "span",
            "marks": [],
            "text": ", well "
          },
          {
            "_key": "56c80ef33b9d10",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "\"Melon Field\""
          },
          {
            "_key": "56c80ef33b9d11",
            "_type": "span",
            "marks": [],
            "text": " refers to an area of melon, but in this case, an area of many categories, so different melons represent different topics. In short, we provide the field (the app) to melon eaters (the user). Name aside, I think it could go either way."
          }
        ],
        "markDefs": [],
        "style": "normal"
      },
      {
        "_key": "c7702a020dde",
        "_type": "block",
        "children": [
          {
            "_key": "ed23c64fc38b0",
            "_type": "span",
            "marks": [
              "strong"
            ],
            "text": "Logo Directions"
          },
          {
            "_key": "ed23c64fc38b1",
            "_type": "span",
            "marks": [],
            "text": "\nWith a clear understanding of the title, I thought maybe adding some personality and fun elements to the logo might help, like having a mascot and being the face of the app. (Fun fact: The mascot has a bitten part, referring to the melon eater idea.)"
          }
        ],
        "markDefs": [],
        "style": "normal"
      }
    ],
